SELECT UPPER(CH.AREA_INGRESSO) AS AREA FROM CALC_HORA_AULA_MEDIA CH JOIN SERVIDOR S ON CH.SIAPE = S.PK_SIAPE WHERE CH.SIGLA_CAMPUS = 'JAT' AND CH.ANO IN (2020,2021,2022,2023) AND LOWER(S.CONTRATO) LIKE LOWER('%efetiv%') GROUP BY CH.AREA_INGRESSO HAVING COUNT(DISTINCT CASE WHEN CH.ANO = 2020 THEN CH.SIAPE END) = 1 AND COUNT(DISTINCT CASE WHEN CH.ANO = 2021 THEN CH.SIAPE END) = 1 AND COUNT(DISTINCT CASE WHEN CH.ANO = 2022 THEN CH.SIAPE END) = 1 AND COUNT(DISTINCT CASE WHEN CH.ANO = 2023 THEN CH.SIAPE END) = 1 ORDER BY CH.AREA_INGRESSO